const user = {
  name: 'Alice',
  tags: ['admin', 'editor'] // Nested array!
};

// ️ Shallow Copy
const shallow = { ...user };
shallow.name = 'Bob'; // Safe! Top level is independent.
shallow.tags.push('super'); //  Bug! Nested array is shared reference.
console.log(user.tags); // ['admin', 'editor', 'super']

//  Deep Copy (Modern JS)
const deep = structuredClone(user);
deep.tags.push('godmode');
console.log(user.tags); // Unchanged. 100% safe.
